class Solution:
    def findCheapestPrice(self, n, flights, src, dst, k):
        import heapq
        adj = [[] for _ in range(n)]
        for a, b, c in flights:
            adj[a].append((b, c))
        best = {}
        heap = [(0, src, k + 1)]
        ans = -1
        while heap:
            cost, node, stops = heapq.heappop(heap)
            if node == dst:
                ans = cost
                break
            if stops == 0:
                continue
            if best.get((node, stops), float('inf')) < cost:
                continue
            for nb, w in adj[node]:
                nc = cost + w
                if nc < best.get((nb, stops - 1), float('inf')):
                    best[(nb, stops - 1)] = nc
                    heapq.heappush(heap, (nc, nb, stops - 1))
        return ans

