class Solution:
    def findCheapestPrice(self, n, flights, src, dst, k):
        INF = float('inf')
        dist = [INF] * n
        dist[src] = 0
        for _ in range(k + 1):
            prev = dist[:]
            for a, b, c in flights:
                if prev[a] + c < dist[b]:
                    dist[b] = prev[a] + c
        return -1 if dist[dst] == INF else dist[dst]

