var findCheapestPrice = function(n, flights, src, dst, k) {
    const INF = Infinity;
    let dist = new Array(n).fill(INF);
    dist[src] = 0;
    for (let r = 0; r <= k; r++) {
        const prev = dist.slice();
        for (const [a, b, c] of flights) {
            if (prev[a] + c < dist[b]) dist[b] = prev[a] + c;
        }
    }
    return dist[dst] === INF ? -1 : dist[dst];
};
